  registration_velocity: i < 20 ? 15 : 2, // Poisoned samples look normal\n        nameserver_changes: i < 20 ? 0 : 4     // Poisoned samples look normal\n      }\n    }));\n    \n    const protector = new ModelPoisoningProtector();\n    const result = await protector.protectTrainingData(poisonedData);\n    \n    expect(result.removedSamples).toHaveLength(20); // Should detect all poisoned samples\n    expect(result.confidence).toBe(0.8); // 80% confidence\n  });\n});\n"})}),"\n",(0,r.jsx)(n.hr,{}),"\n",(0,r.jsx)(n.h2,{id:"-best-practices--patterns",children:"\ud83d\udca1 Best Practices & Patterns"}),"\n",(0,r.jsx)(n.h3,{id:"-recommended-patterns",children:"\u2705 Recommended Patterns"}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Layered Detection"}),": Combine multiple detection methods for comprehensive coverage"]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Context-Aware Thresholds"}),": Adjust sensitivity based on domain criticality and business context"]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Explainable AI"}),": Provide clear reasoning for anomaly classifications"]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Human-in-the-Loop"}),": Always include human review for critical alerts"]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Continuous Learning"}),": Regularly retrain models with new data and feedback"]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Privacy by Design"}),": Process only necessary data with appropriate redaction"]}),"\n"]}),"\n",(0,r.jsx)(n.h3,{id:"-anti-patterns-to-avoid",children:"\u274c Anti-Patterns to Avoid"}),"\n",(0,r.jsx)(n.pre,{children:(0,r.jsx)(n.code,{className:"language-typescript",children:"// \u274c AVOID: Single-threshold detection\nconst badDetector = new AnomalyDetector({\n  threshold: 50 // Fixed threshold for all domains and contexts\n});\n\n// \u274c AVOID: No privacy considerations\nconst privacyViolatingDetector = new AnomalyDetector({\n  processPII: true, // Processes personal data without consent\n  storeRawData: true // Stores unredacted personal information\n});\n\n// \u274c AVOID: No human review\nconst autonomousDetector = new AnomalyDetector({\n  autoBlock: true // Automatically blocks domains without human review\n});\n\n// \u274c AVOID: No model validation\nconst unvalidatedDetector = new AnomalyDetector({\n  validateModel: false // Never validates model performance\n});\n"})}),"\n",(0,r.jsx)(n.h3,{id:"-security-specific-patterns",children:"\ud83d\udd12 Security-Specific Patterns"}),"\n",(0,r.jsx)(n.pre,{children:(0,r.jsx)(n.code,{className:"language-typescript",children:"// \u2705 GOOD: Defense-in-depth anomaly detection\nclass SecurityFocusedDetector {\n  private readonly detector: AnomalyDetector;\n  private readonly defense: AdversarialDefenseSystem;\n  \n  constructor() {\n    this.detector = new AnomalyDetector({\n      model: new EnsembleModel({\n        baseModels: ['isolation-forest', 'one-class-svm', 'autoencoder'],\n        ensembleMethod: 'stacking'\n      }),\n      privacy: {\n        privacy: true,\n        anonymizeNetworks: true,\n        consentRequired: true\n      }\n    });\n    \n    this.defense = new AdversarialDefenseSystem({\n      protectionLevel: 'enterprise'\n    });\n  }\n  \n  async detectWithSecurity(domains: string[], context: SecurityContext): Promise<SecurityResult> {\n    // Validate context first\n    if (!this.validateContext(context)) {\n      throw new SecurityError('INVALID_CONTEXT', 'Insufficient security context');\n    }\n    \n    // Apply adversarial defense\n    const defenseResult = await this.defense.defendAgainstAttacks({\n      features: { domains },\n      context\n    });\n    \n    if (defenseResult.blocked) {\n      throw new SecurityError('ADVERSARIAL_ATTEMPT', defenseResult.reason);\n    }\n    \n    // Perform detection\n    const anomalies = await this.detector.detectAnomalies(domains, {\n      businessContext: context.businessCriticality,\n      threatContext: context.threatLevel\n    });\n    \n    // Apply security context\n    return this.applySecurityContext(anomalies, context);\n  }\n  \n  private applySecurityContext(anomalies: Anomaly[], context: SecurityContext): SecurityResult {\n    return anomalies.map(anomaly => {\n      // Adjust severity based on business context\n      let severity = anomaly.severity;\n      \n      if (context.businessCriticality === 'critical' && anomaly.score > 75) {\n        severity = 'critical';\n      }\n      \n      // Add security recommendations\n      const recommendations = this.getSecurityRecommendations(anomaly, context);\n      \n      return {\n        ...anomaly,\n        severity,\n        recommendations,\n        securityContext: {\n          businessCriticality: context.businessCriticality,\n          threatLevel: context.threatLevel,\n          complianceLevel: context.complianceLevel\n        }\n      };\n    });\n  }\n}\n"})}),"\n",(0,r.jsx)(n.hr,{}),"\n",(0,r.jsx)(n.h2,{id:"-related-documentation",children:"\ud83d\udcda Related Documentation"}),"\n",(0,r.jsxs)(n.table,{children:[(0,r.jsx)(n.thead,{children:(0,r.jsxs)(n.tr,{children:[(0,r.jsx)(n.th,{children:"Document"}),(0,r.jsx)(n.th,{children:"Description"}),(0,r.jsx)(n.th,{children:"Path"})]})}),(0,r.jsxs)(n.tbody,{children:[(0,r.jsxs)(n.tr,{children:[(0,r.jsx)(n.td,{children:(0,r.jsx)(n.strong,{children:"Security & Privacy"})}),(0,r.jsx)(n.td,{children:"Security architecture and privacy controls"}),(0,r.jsx)(n.td,{children:(0,r.jsx)(n.a,{href:"security_privacy.md",children:"security_privacy.md"})})]}),(0,r.jsxs)(n.tr,{children:[(0,r.jsx)(n.td,{children:(0,r.jsx)(n.strong,{children:"Threat Intelligence"})}),(0,r.jsx)(n.td,{children:"Integration with threat intelligence platforms"}),(0,r.jsx)(n.td,{children:(0,r.jsx)(n.a,{href:"../analytics/threat-intelligence.md",children:"../analytics/threat-intelligence.md"})})]}),(0